var SITE_DATA = {"hero":{"badge":"✦ 少儿美术教育 ✦","title1":"用","highlight":"爱与专业","title2":"守护每一个艺术梦想","subtitle":"合肥咔乐艺术培训中心 · 专注3-16岁少儿艺术教育\n小班教学 · 名师指导 · 让孩子在色彩中自信成长","stats":[{"num":"9年","label":"办学经验"},{"num":"5000+","label":"培养学员"},{"num":"99%","label":"考级通过率"},{"num":"300+","label":"获奖人次"}]},"about":{"title":"一所真正懂孩子的艺术学校","p1":"合肥咔乐艺术培训中心创办于2018年，是一所经教育部门批准设立的专业少儿艺术培训机构。我们坚信：每个孩子都是天生的艺术家，老师的职责是引导而非灌输，是点燃而非填塞。","p2":"我们采用「观察+启发+创作」三位一体的教学法，根据每个孩子的个性与能力定制教学方案，让艺术成为孩子表达自我、认知世界的快乐方式。","features":[{"icon":"👩‍🎓","title":"专业师资","desc":"全部持教师资格证上岗"},{"icon":"👥","title":"小班教学","desc":"每班6-12人，关注每个孩子"},{"icon":"📐","title":"科学体系","desc":"分龄分阶，循序渐进"},{"icon":"🏆","title":"成果可见","desc":"定期作品展 + 参赛辅导"}]},"coursesSection":{"subtitle":"分龄分阶，从兴趣启蒙到专业进阶"},"courses":[{"id":1,"name":"少儿水彩启蒙班","icon":"🖌️","cls":"watercolor","age":"3-8岁","desc":"通过水彩游戏激发色彩感知，培养观察力与想象力，让孩子在玩中感受色彩魅力。","detail":"以水彩为媒介，通过趣味游戏引导孩子认识颜色、感受色彩变化。课堂设置「色彩小实验」「故事涂鸦」「合作大画」等环节，在玩中建立对美术的第一份好感。","teacher":"高高老师","duration":"90分钟/次","classSize":"6-12人","price":"¥1080/15课时","stages":[{"step":"01","name":"感知色彩"},{"step":"02","name":"自由涂鸦"},{"step":"03","name":"简单造型"}]},{"id":2,"name":"素描进阶班","icon":"✏️","cls":"sketch","age":"9-15岁","desc":"系统学习线条、明暗、透视，打下扎实的造型基础，为后续专业学习做好准备。","detail":"从握笔姿势和线条练习开始，逐步学习几何体、静物、风景素描。每节课配合范画讲解和一对一指导，帮助孩子建立\"观察—分析—表达\"的完整绘画思维。","teacher":"彤彤","duration":"120分钟/次","classSize":"6-12人","price":"¥1260/15课时","stages":[{"step":"01","name":"线条基础"},{"step":"02","name":"明暗关系"},{"step":"03","name":"透视构图"}]},{"id":3,"name":"国画入门班","icon":"🖋️","cls":"inkart","age":"8-14岁","desc":"从写意花鸟到山水小品，感受中国传统水墨之美，培养文化自信与审美底蕴。","detail":"从认识文房四宝开始，学习执笔、运墨、调色。以花鸟鱼虫为切入点，逐步过渡到山水画创作。融入诗词赏析，让孩子在笔墨间感受传统文化的魅力。","teacher":"小小老师","duration":"90分钟/次","classSize":"6-12人","price":"¥1080/15课时","stages":[{"step":"01","name":"毛笔基础"},{"step":"02","name":"写意花鸟"},{"step":"03","name":"山水小品"}]},{"id":4,"name":"硬笔书法班","icon":"📜","cls":"calligraphy","age":"5-12岁","desc":"规范书写姿势与笔法，提升卷面整洁度，同时培养专注力与耐心。","detail":"从纠正坐姿和握笔姿势开始，系统学习基本笔画、偏旁部首和间架结构。配合学校语文课本生字练习，既能写好字又能巩固课堂所学。","teacher":"孙瑞老师","duration":"90分钟/次","classSize":"8-12人","price":"¥1,260/15课时","stages":[{"step":"01","name":"坐姿执笔"},{"step":"02","name":"基本笔画"},{"step":"03","name":"间架结构"}]},{"id":5,"name":"线描 & 卡漫班","icon":"✏️","cls":"oil","age":"7-16岁","desc":"学习线条表现力与漫画创作技巧，培养角色设计和叙事表达能力。","detail":"系统学习线条的表现力，从基础素描到漫画创作。学习角色设计、分镜绘制和故事叙述，培养动漫创作的综合能力。","teacher":"文子老师","duration":"90分钟/次","classSize":"4-6人","price":"¥1080/15课时","stages":[{"step":"01","name":"线条基础"},{"step":"02","name":"角色设计"},{"step":"03","name":"故事创作"}]},{"id":6,"name":"创意手工 & 绘本创作","icon":"🌈","cls":"creative","age":"4-8岁","desc":"综合运用多种材料，从平面到立体，让孩子动手创造属于自己的故事世界。","detail":"结合撕纸、拼贴、泥塑、综合材料等多种形式，让孩子从\"动手玩\"过渡到\"有想法地创作\"。最终每个孩子都能完成一本属于自己的原创绘本故事。","teacher":"小小","duration":"90分钟/次","classSize":"6-8人","price":"¥1,280/16课时","stages":[{"step":"01","name":"撕纸拼贴"},{"step":"02","name":"立体造型"},{"step":"03","name":"完整绘本"}]},{"id":1779354605300,"name":"舞蹈中国舞","icon":"跳舞","cls":"Dance","age":"4-12","desc":"中国舞融合古典身韵与民族体态，以软开、形体、舞姿、节奏为基础。不只是练跳舞，更锻炼孩子挺拔体态、优雅气质与肢体控制力，培养耐心、自信与古典审美，让孩子身姿端正、仪态大方。","detail":"少儿中国舞课程循序渐进开展基本功、软开训练，融入古典身韵与多民族舞蹈。科学矫正不良体态，塑造优雅身形，同时学习成品剧目，锻炼肢体协调性与表现力，培养孩子自信心与东方艺术气质，零基础也可轻松学习。","teacher":"徐老师","duration":"90分钟","classSize":"6-12","price":"1080/15课时","stages":[{"step":"01","name":"启蒙阶段 4-5岁"},{"step":"02","name":"初级阶段 6-8岁"},{"step":"03","name":"中级阶段 9-11岁"},{"step":"04","name":"高级阶段 12岁以上"}]}],"teachersSection":{"subtitle":"用专业与热爱，陪伴每一个孩子的艺术成长"},"teachers":[{"id":1,"name":"孙习文（文子老师）","avatar":"👩‍🎨","tagline":"一笔一画教画画，一言一行育品格","school":"合肥师范学院","degree":"本科","cert":"小学美术教师资格证","years":"8年","role":"少儿水彩启蒙班 / 素描进阶班","philosophy":"重观察启思维，轻模板固思维，因材施教","specialties":"水彩 ，儿童创意美术 ，素描基础 ，绘本创作 ，国画入门","achievements":"成果 1\n荣获全国第二十四届蒲公英优秀书画迎春展活动“优秀教师”\n成果 2\n所带班级美术考级通过率 100%\n成果3\n合肥白名单赛事安徽赛区优秀指导教师","quote":"授绘画之技，立审美之根","message":"亲爱的家长朋友们，艺术教育不止教会孩子提笔作画，更重在滋养心灵、涵养审美。在课堂上我尊重每个孩子独特的想象力与创作思维，不刻板拘束、不固化模板，用心引导孩子感受色彩与线条的美好。","avatarClass":"t1","avatarBg":""},{"id":2,"name":"侯霞艳（高高老师）","avatar":"👨‍🏫","tagline":"守护孩子的艺术天性，引导审美能力成长","school":"宿州学院","degree":"本科","cert":"小学美术教师资格","years":"6年","role":"少儿创意美术，动漫创意，素描","philosophy":"用心引导孩子感受美、创造美，耐心守护每份童真与想象，用真诚与细致陪伴孩子在艺术路上自信成长。","specialties":"水彩 / 儿童创意美术 / 动漫入门/ 高阶卡漫 / 素描基础/水粉","achievements":"成果 1\n荣获全国第二十四届蒲公英优秀书画迎春展活动“优秀教师”\n成果 2\n所带班级美术考级通过率 100%","quote":"用真心换家长放心[爱心]","message":"教育没有捷径，唯有真心换放心。我始终用心陪伴孩子成长，珍视每一次点滴进步，认真对待每一幅作品。孩子展出的每一幅画，都是脚踏实地的成长印记。我会用专业与耐心，守护孩子热爱，助力每一个小小的艺术梦想生根发芽。","avatarClass":"t2","avatarBg":""},{"id":3,"name":"孙宏英（英子老师）","avatar":"👩‍🎓","tagline":"执笔传墨，静心育人","school":"合肥学院基础教育专业","degree":"专科","cert":"幼儿教师资格证","years":"18年","role":"硬笔书法","philosophy":" 以规范练字为基，以静心修德为本，写方正汉字，育端正品格。","specialties":"硬笔楷书规范教学、应试书写、考级辅导、练字习惯养成","achievements":"拥有多年少儿硬笔教学经验，帮助众多孩子改善字迹潦草、大小不均、书写浮躁等问题；显著提升日常作业整洁度与考试卷面分数，多名学员顺利通过书法考级、在校级书写比赛中获奖，让孩子在练字中沉淀耐心、养成好习惯。","quote":"执硬笔守规矩，写汉字养气度","message":"练字先正姿，习字先修心。我专注少儿硬笔楷书教学，重视书写习惯培养与应试卷面提升，用心教会孩子规范书写、静心做事。教育贵在坚持，愿与家长携手，陪伴孩子写好字、做好人。","avatarClass":"t3","avatarBg":""},{"id":4,"name":"孙瑞","avatar":"👨‍🏫","tagline":"一手好字，自信一生","school":"安徽职业技术大学 ","degree":"大专","cert":"小学书法老师","years":"5年","role":"硬笔书法班","philosophy":"我从不教孩子\"应该怎么画\"，而是帮他们发现\"原来我可以这样画\"。每个孩子的笔触都是独一无二的语言，老师要做的不是纠正，而是看见和引导。","specialties":"硬笔书法,楷书,行书,作业快写体","achievements":"学员书法考级通过率达100%；辅导学员多次荣获全国硬笔书法比赛金奖、银奖、特等奖等重要奖项","quote":"\"不是写快写多，而是让孩子放下急躁，在笔画里慢慢静下来。\"","message":"硬笔书法这件事，说到底我们不仅要把每个孩子都练成写字高手。课堂上，我还要在意的是：孩子能不能在横平竖直里学会坐得住、静下来。字写工整了，卷面自然少扣分；但比分数更重要的，是那份不急不躁的定力。","avatarClass":"t4","avatarBg":"linear-gradient(135deg, #e8f0e5, #d4e5cf)"},{"id":1779356646406,"name":"王心彤（彤彤老师）","avatar":"👩‍🏫","tagline":"学无止境，勇于攀登","school":"阜阳幼儿师范学院美术教育专业","degree":"专科","cert":"小学教师资格证","years":"4年","role":"硬笔书法/国画/素描老师","philosophy":"知识不止在课内，还在生活中。成长的过程中拥有许多可能。","specialties":"书法/素描基础 / 手工制作/中 国画/提升孩子文化素养/习惯培养","achievements":"成果 1\n荣获全国第二十四届蒲公英优秀书画迎春展活动“优秀教师”\n成果 2\n所带班级美术考级通过率 100%","quote":"[手抖了、线歪了都没事，你的每一笔都算数。]","message":"学习不是一蹴而就的，它有许多的过程，或失落、或喜悦、或收获、或迷茫。它不是一帆风顺，它是人生的一段旅程。路上风景很美，你要慢慢去看吗？","avatarClass":"","avatarBg":""},{"id":1779356757922,"name":"杨惠敏（小小老师）","avatar":"👩‍🏫","tagline":"以美育人，以艺养心","school":"合肥师范美术专业","degree":"本科","cert":"小学美术教师资格证","years":"10年","role":"少儿美术","philosophy":"尊重童心，守护创意。教学不止于绘画技巧，更重在激发想象力，观察力与创造力。鼓励大胆表达，自由创作，让孩子在色彩与线条中感受快乐，学会发现美，感受美，创造美。","specialties":"卡漫/水彩/儿童创意美术/素描/绘本创作/国画","achievements":"成果1\n荣获全国第二十四届蒲公英优秀书画迎春展活动\"优秀教师\"\n成果2\n所带班级美术考级通过率100%","quote":"快乐画画，大胆想象，自在表达。","message":"在美术课堂上，我不只教孩子画画技巧，更注重保护孩子的想象力与创造力。每个孩子笔下的世界都是独一无二的，我会耐心引导，鼓励表达，不束缚思维，不固化模板。愿我们家校同心，一起守护孩子对美的热爱，让孩子大胆创作，快乐成长。\n","avatarClass":"","avatarBg":""}],"achievements":{"stats":[{"num":"12+","label":"合肥市少儿绘画大赛一等奖人次"},{"num":"99%","label":"美术考级通过率"},{"num":"3项","label":"全国少儿书画大赛金奖"},{"num":"1000+","label":"累计培养学员"}],"highlights":[{"icon":"🏆","title":"全国第二十四届蒲公英优秀书画迎春展","desc":"胡芯宇《银蛇舞春》入选全国二十四届蒲公英优秀书画迎春展"},{"icon":"🎖️","title":"多名学员考入知名艺术类高中","desc":"文子老师辅导的考前班学员升学成果优异"},{"icon":"⭐","title":"连续3年\"最受欢迎教师\"","desc":"小小老师获评咔乐艺术年度最受欢迎教师"},{"icon":"📚","title":"\"趣味水墨\"系列课程","desc":"彤彤老师自主开发课程获家长一致好评"}]},"campusSection":{"subtitle":"安全、舒适、充满艺术氛围的学习空间"},"campus":[{"icon":"🖼️","label":"水彩画室","image":"data:image/jpeg;base64,"},{"icon":"📚","label":"绘本阅读角","image":"data:image/jpeg;base64,"},{"icon":"🎨","label":"创意走廊","image":"data:image/jpeg;base64,"},{"icon":"🖋️","label":"书法教室","image":"data:image/jpeg;base64,"},{"icon":"🏠","label":"前台接待区","image":"data:image/jpeg;base64,"},{"icon":"🌿","label":"户外写生区","image":"data:image/jpeg;base64,"}],"admissionsSection":{"subtitle":"2026年暑期班火热招生中"},"admissions":[{"id":1,"title":"🎨 兴趣启蒙班","price":"¥1080","priceUnit":"/ 15课时","featured":true,"features":["适合年龄：3-6岁","水彩涂鸦 + 创意手工","每班 6-10人以内","每周 1 次，90 分钟/次","免费试听一节"]},{"id":2,"title":"⭐ 综合美术班","price":"1080-1260","priceUnit":"/ 15课时","featured":true,"features":["适合年龄：6-12岁","素描 + 水彩 + 国画轮转","每班 12 人以内","每周 1-2 次，90-120分钟/次","赠送全套画材"]},{"id":3,"title":"🚀 专业进阶班","price":"¥1260","priceUnit":"/ 15课时","featured":true,"features":["适合年龄：9-16岁","油画 + 色彩理论 + 考前辅导","每班 8人以内","每周 2 次，120 分钟/次","一对一升学规划"]},{"id":1779357406377,"title":"✍️","price":"1260","priceUnit":"/15课时","featured":true,"features":["适合年龄：3-12岁","双姿调整/控笔训练","90分钟/次课","一手好字 自信一生"]},{"id":1779357460452,"title":"💃","price":"1080","priceUnit":"/15课时","featured":true,"features":["适合年龄：4-12岁","中国舞/体态气质/兴趣培养","90分钟/课时"]}],"testimonials":[{"stars":5,"text":"孩子在这儿学了两年了，从不敢下笔到现在每周都盼着来上课。小小老师特别有耐心，每次课后都会主动跟我们沟通孩子的进步和需要加强的地方。真心推荐！","author":"—— 小雨妈妈 · 学员7岁 · 学习2年"},{"stars":5,"text":"对比了好几家美术机构，最终选了咔乐。环境好、老师专业、课程体系科学。最重要的是孩子开心！每次拿着作品出来，眼睛都是亮的。","author":"—— 浩浩爸爸 · 学员5岁 · 学习半年"},{"stars":5,"text":"彤彤老师老师太厉害了，我女儿今年顺利考上了二中美术班！从零基础到专业水平，每一步都有咔乐老师的陪伴和指导。感谢你们！","author":"—— 思涵妈妈 · 学员14岁 · 学习3年"}],"faq":[{"q":"孩子几岁开始学画画比较合适？","a":"3-4岁就可以开始接触涂鸦和色彩游戏，培养感知力；5-6岁可以开始简单的造型训练；7岁以上可以系统学习素描、国画等。最重要的是尊重孩子的兴趣和节奏，不急于求成。"},{"q":"试听课怎么预约？收费吗？","a":"试听课完全免费！您可以通过电话、微信联系我们，告知孩子年龄和感兴趣的方向，我们会安排最适合的老师和时段。试听后不报名也没有任何压力。"},{"q":"一个班几个孩子？老师顾得过来吗？","a":"启蒙班不超过8人，综合班不超过10人，进阶班不超过6人。我们坚持小班教学，确保每位老师能关注到每个孩子的学习状态，给予个性化指导。"},{"q":"画材需要自己准备吗？","a":"启蒙班学费已包含全部画材费用，孩子直接来上课即可。综合美术班和专业进阶班我们也会提供基础画材，如有额外需求老师会提前通知。"}],"contact":{"title":"欢迎预约免费试听，带孩子来感受艺术的魅力","subtitle":"CONTACT","items":[{"icon":"📍","title":"地址","content":"合肥市肥西县上派镇水晶城商业街A15栋2层咔乐艺术"},{"icon":"📞","title":"电话","content":"17755123937"},{"icon":"💬","title":"微信","content":"D_D-D_D-D_D"},{"icon":"🕐","title":"咨询时间","content":"周一至周日 9:00-18:00"}]},"news":[{"title":"2026年春季班招生开始啦！","date":"2026-03-01","content":"新学期新气象，咔乐艺术2026年春季班开始招生了！开设水彩、素描、国画、书法、舞蹈等多个课程，欢迎小朋友们报名学习。"}]};